1176	func parsePreExecuteCheckpointDirtyPaths(detail string) []string {
1177		idx := strings.Index(detail, preDispatchCheckpointDirtyRefusalPrefix)
1178		if idx == -1 {
1179			return nil
1180		}
1181		pathsField := detail[idx+len(preDispatchCheckpointDirtyRefusalPrefix):]
1182		if semi := strings.Index(pathsField, ";"); semi >= 0 {
1183			pathsField = pathsField[:semi]
1184		}
1185		var paths []string
1186		for _, path := range strings.Split(pathsField, ",") {
1187			path = strings.TrimSpace(path)
1188			if path != "" {
1189				paths = append(paths, path)
1190			}
1191		}
1192		return paths
1193	}
