1264	func normalizeDirtyRootPaths(paths []string) []string {
1265		if len(paths) == 0 {
1266			return nil
1267		}
1268		uniq := make(map[string]struct{}, len(paths))
1269		normalized := make([]string, 0, len(paths))
1270		for _, path := range paths {
1271			path = strings.TrimSpace(path)
1272			if path == "" {
1273				continue
1274			}
1275			if _, ok := uniq[path]; ok {
1276				continue
1277			}
1278			uniq[path] = struct{}{}
1279			normalized = append(normalized, path)
1280		}
1281		if len(normalized) == 0 {
1282			return nil
1283		}
1284		sort.Strings(normalized)
1285		return normalized
1286	}
