1295	func updateDirtyRootGuardState(projectRoot string, dirtyPaths []string, at time.Time, threshold int, cooldown time.Duration) (*dirtyRootGuardState, bool, error) {
1296		if projectRoot == "" {
1297			return nil, false, nil
1298		}
1299		if threshold <= 0 {
1300			threshold = DefaultDirtyRootEscalationThreshold
1301		}
1302		if cooldown <= 0 {
1303			cooldown = DirtyRootEscalationCooldown
1304		}
1305		paths := normalizeDirtyRootPaths(dirtyPaths)
1306		if len(paths) == 0 {
1307			if err := clearDirtyRootGuardState(projectRoot); err != nil {
1308				return nil, false, err
1309			}
1310			return nil, false, nil
1311		}
1312		fingerprint := dirtyRootPathFingerprint(paths)
1313		state, err := readDirtyRootGuardState(projectRoot)
1314		if err != nil {
1315			return nil, false, err
1316		}
1317		next := dirtyRootGuardState{
1318			Fingerprint:     fingerprint,
1319			DirtyPaths:      append([]string(nil), paths...),
1320			Count:           1,
1321			FirstObservedAt: at.UTC(),
1322			LastObservedAt:  at.UTC(),
1323		}
1324		if state != nil && state.Fingerprint == fingerprint {
1325			next.FirstObservedAt = state.FirstObservedAt
1326			if next.FirstObservedAt.IsZero() {
1327				next.FirstObservedAt = at.UTC()
1328			}
1329			next.Count = state.Count
1330			next.RetryAfter = state.RetryAfter
1331			if state.RetryAfter.After(at) {
1332				// The cooldown is still active. Preserve the existing marker so the
1333				// relaunch sees the same backoff instead of tightening the spin loop.
1334				next.Count = state.Count
1335				next.RetryAfter = state.RetryAfter
1336				if err := writeDirtyRootGuardState(projectRoot, next); err != nil {
1337					return nil, false, err
1338				}
1339				return &next, true, nil
1340			}
1341			next.Count = state.Count + 1
1342			if next.Count >= threshold {
1343				next.RetryAfter = at.UTC().Add(cooldown)
1344			} else {
1345				next.RetryAfter = time.Time{}
1346			}
1347		} else {
1348			next.Count = 1
1349			next.RetryAfter = time.Time{}
1350		}
1351		if next.Count >= threshold && next.RetryAfter.IsZero() {
1352			next.RetryAfter = at.UTC().Add(cooldown)
1353		}
1354		if err := writeDirtyRootGuardState(projectRoot, next); err != nil {
1355			return nil, false, err
1356		}
1357		return &next, next.Count >= threshold, nil
1358	}
