1360	// isTransientGitContention reports git index/ref contention errors that are
1361	// transient under concurrent workers and must be retried rather than treated
1362	// as a worker-stopping failure (ddx-23ac2796 and its sibling variants). The
1363	// gitlock package owns the shared output/error classifier for the concrete git
1364	// forms; this wrapper adds the DDx tracker-lock timeout sentinel and the
1365	// context-deadline cases used by the loop's durable-audit stop logic.
1366	func isTransientGitContention(err error) bool {
1367		if err == nil {
1368			return false
1369		}
1370		if errors.Is(err, TrackerLockTimeoutErr) {
1371			return true
1372		}
1373		if errors.Is(err, context.DeadlineExceeded) {
1374			return true
1375		}
1376		return gitlock.IsTransientGitContention("", err)
1377	}
